fun solveCase(s: String): Int { val stack = mutableListOf(-1); var best = 0; for (i in s.indices) { if (s[i] == '(') stack.add(i) else { stack.removeAt(stack.size - 1); if (stack.isEmpty()) stack.add(i) else best = maxOf(best, i - stack.last()) } }; return best }
fun main(){ val lines=generateSequence(::readLine).toList(); if(lines.isEmpty()) return; var idx=0; val t=lines[idx++].trim().toInt(); val out=mutableListOf<String>(); repeat(t){ val n=if(idx<lines.size) lines[idx++].trim().toInt() else 0; val s=if(n>0 && idx<lines.size) lines[idx++] else ""; out.add(solveCase(s).toString()) }; print(out.joinToString("\n")) }
